#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> eventualSafeNodes(vector<vector<int>>& graph) {
        int n = graph.size();
        vector<vector<int>> rev_graph(n);
        vector<int> out_degree(n, 0);
        for (int i = 0; i < n; i++) {
            for (int j : graph[i]) {
                rev_graph[j].push_back(i);
                out_degree[i]++;
            }
        }

        queue<int> q;
        for (int i = 0; i < n; i++) {
            if (out_degree[i] == 0) {
                q.push(i);
            }
        }
        vector<int> safe_nodes;

        while (!q.empty()) {
            int node = q.front();
            q.pop();
            safe_nodes.push_back(node);
            for (int neighbor : rev_graph[node]) {
                out_degree[neighbor]--;
                if (out_degree[neighbor] == 0) {
                    q.push(neighbor);
                }
            }
        }
        sort(safe_nodes.begin(), safe_nodes.end());
        return safe_nodes;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<vector<int>> graph(n);
    for (int i = 0; i < n; i++) {
        int m;
        cin >> m;
        graph[i].resize(m);
        for (int j = 0; j < m; j++) {
            cin >> graph[i][j];
        }
    }
    Solution sol;
    vector<int> ans = sol.eventualSafeNodes(graph);
    cout << ans.size() << "\n";
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
